function magazynQRCentrumHTML(){
  const locations=typeof magazynLokalizacjeAktywne==="function"?magazynLokalizacjeAktywne():[];
  return `<section class="panel warehouse-qr-center warehouse-qr-page"><div class="order-section-head"><div><span class="order-pro-label">Centrum oznaczeń magazynowych</span><h2>Wybór i przygotowanie etykiet</h2><p class="order-detail-lead">Twórz, zaznaczaj i drukuj etykiety dla obszarów, regałów, półek, miejsc oraz produktów. Generator nie zmienia stanów ani kartotek — przygotowuje wyłącznie bezpieczne oznaczenia do skanowania.</p></div><div class="warehouse-qr-page-actions"><span class="warehouse-qr-ready">${locations.length?"✅":"⚠️"} ${locations.length} lokalizacji gotowych</span><a class="btn ghost" href="#/admin/magazyn/lokalizacje">🗺️ Zarządzaj lokalizacjami</a><a class="btn ghost" href="#/admin/magazyn/plan">📦 Przejdź do PZ/WZ</a></div></div><div class="warehouse-qr-flow"><span><b>1</b><strong>Wybierz zakres</strong><small>lokalizacje albo produkty</small></span><span><b>2</b><strong>Zaznacz pozycje</strong><small>pojedynczo lub grupowo</small></span><span><b>3</b><strong>Wybierz format</strong><small>62×38, 70×50 lub A4</small></span><span><b>4</b><strong>Drukuj lub zapisz PDF</strong><small>gotowe do użycia telefonem</small></span></div><section class="warehouse-qr-generator"><header class="warehouse-qr-generator-head"><span><b>🏷️ Generator etykiet QR</b><small>Druk dla regałów, półek, miejsc i konkretnych produktów.</small></span><strong>Dane pozostają w sklepie</strong></header><div id="warehouseQrWorkspace">${magazynQRGeneratorWnetrzeHTML()}</div></section><div class="warehouse-qr-page-note"><b>📱 Jak używać po wydruku?</b><span>W Planie zatowarowania otwórz PZ albo WZ, uruchom aparat telefonu, zeskanuj najpierw lokalizację, a następnie produkty.</span></div></section>`;
}
function magazynQREtykietaDane(type,id){
  if(type==="L"){const l=magazynLokalizacjaPoKodzie(id);if(!l)return null;const area=magazynQRStrefaNazwa(l),parent=l.parentKod?magazynLokalizacjaPoKodzie(l.parentKod):null;return {type:"location",payload:magazynQRPayloadLokalizacji(l.kod),short:magazynQRLokalizacjaSkrot(l),typeLabel:`${area} • ${magazynEtykietaTypuLokalizacji(l.typ)}`.toUpperCase(),title:magazynQRLokalizacjaSkrot(l),subtitle:l.typ==="strefa"?area:[parent?.nazwa,l.nazwa].filter(Boolean).join(" • "),meta:""};}
  const p=magazynQRProduktPoId(id);if(!p)return null;const meta=magazynMetaProduktu(p.id),identifier=p.externalId||p.sku||`ID ${p.id}`;return {type:"product",payload:magazynQRPayloadProduktu(p.id),short:identifier,typeLabel:"PRODUKT",title:p.nazwa||`Produkt ${p.id}`,subtitle:identifier,meta:`EAN ${p.gtin||p.ean||"—"}${meta.lokalizacja?` • ${meta.lokalizacja}`:""}`};
}
function magazynQRSvg(payload){const qr=window.qrcode(0,"M");qr.addData(String(payload),"Byte");qr.make();return qr.createSvgTag({cellSize:4,margin:2,scalable:true});}
function magazynQREtykietyHTML(items){return items.map(item=>`<article class="warehouse-qr-label label-${item.type}"><div class="warehouse-qr-code" aria-label="Kod QR: ${esc(item.title)}">${magazynQRSvg(item.payload)}</div><div class="warehouse-qr-label-copy"><span>${esc(item.typeLabel||item.type)}</span><strong>${esc(item.short||item.title)}</strong>${item.type!=="location"?`<b>${esc(item.title)}</b>`:""}<small>${esc(item.subtitle)}</small>${item.meta?`<em>${esc(item.meta)}</em>`:""}</div></article>`).join("");}
function magazynQREtykietyDoPodgladu(){const copies=Math.max(1,Math.min(20,Number(magazynQRKopie)||1)),result=[];for(const item of magazynQRPodgladPozycje)for(let copy=0;copy<copies;copy++)result.push(item);return result;}
function magazynQRUstawKopie(value){magazynQRKopie=Math.max(1,Math.min(20,Math.trunc(Number(value)||1)));const sheet=document.getElementById("warehouseQrPrintArea"),counter=document.querySelector("[data-warehouse-qr-preview-count]");if(sheet)sheet.innerHTML=magazynQREtykietyHTML(magazynQREtykietyDoPodgladu());if(counter)counter.textContent=String(magazynQREtykietyDoPodgladu().length);}
async function magazynQROtworzPodglad(keys=[...magazynQRZaznaczone]){
  if(!keys.length){toast("Zaznacz co najmniej jedną etykietę");return;}
  try{await magazynQRLadujGenerator();const items=keys.map(key=>{const pos=String(key).indexOf(":");return magazynQREtykietaDane(String(key).slice(0,pos),String(key).slice(pos+1));}).filter(Boolean).sort((a,b)=>magazynQRPorownajNaturalnie(`${a.type} ${a.subtitle}`,`${b.type} ${b.subtitle}`)).slice(0,500);if(!items.length){toast("Nie znaleziono danych etykiet");return;}magazynQRPodgladPozycje=items;
    document.getElementById("warehouseQrPreview")?.remove();const modal=document.createElement("div");modal.id="warehouseQrPreview";modal.className="warehouse-qr-preview";modal.innerHTML=`<div class="warehouse-qr-preview-card"><header><div><b>🏷️ Podgląd przed drukiem</b><small><span data-warehouse-qr-preview-count>${magazynQREtykietyDoPodgladu().length}</span> etykiet • na wydruku znajdą się wyłącznie wybrane pozycje</small></div><div class="warehouse-qr-preview-controls"><label>Format<select onchange="magazynQRZmienFormat(this.value)"><option value="62x38" ${magazynQRFormat==="62x38"?"selected":""}>62 × 38 mm — jedna etykieta na stronę</option><option value="70x50" ${magazynQRFormat==="70x50"?"selected":""}>70 × 50 mm — jedna etykieta na stronę</option><option value="a4" ${magazynQRFormat==="a4"?"selected":""}>A4 — siatka etykiet</option></select></label><label>Liczba kopii<input type="number" min="1" max="20" value="${esc(magazynQRKopie)}" onchange="magazynQRUstawKopie(this.value)"></label><button class="btn" type="button" onclick="magazynQRDrukuj()">🖨️ Drukuj / zapisz PDF</button><button class="btn ghost" type="button" onclick="magazynQRZamknijPodglad()">Zamknij</button></div></header><div class="warehouse-qr-print-help"><b>${magazynQRFormat==="a4"?"Arkusz A4":"Drukarka etykiet"}</b><span>${magazynQRFormat==="a4"?"Etykiety zostaną ułożone automatycznie na kolejnych stronach.":"Każdy QR otrzyma osobną stronę dokładnie w wybranym rozmiarze."}</span></div><div id="warehouseQrPrintArea" class="warehouse-qr-sheet format-${esc(magazynQRFormat)}">${magazynQREtykietyHTML(magazynQREtykietyDoPodgladu())}</div></div>`;document.body.appendChild(modal);
  }catch(error){toast(`Nie udało się przygotować QR: ${error.message||error}`);}
}
function magazynQROtworzJedna(type,id){return magazynQROtworzPodglad([magazynQRKlucz(type,id)]);}
function magazynQROtworzLokalizacje(kod){return magazynQROtworzJedna("L",kod);}
function magazynQROtworzProdukt(id){return magazynQROtworzJedna("P",id);}
function magazynQRZmienFormat(value){magazynQRFormat=["62x38","70x50","a4"].includes(value)?value:"62x38";const sheet=document.getElementById("warehouseQrPrintArea"),help=document.querySelector(".warehouse-qr-print-help");if(sheet)sheet.className=`warehouse-qr-sheet format-${magazynQRFormat}`;if(help)help.innerHTML=magazynQRFormat==="a4"?"<b>Arkusz A4</b><span>Etykiety zostaną ułożone automatycznie na kolejnych stronach.</span>":"<b>Drukarka etykiet</b><span>Każdy QR otrzyma osobną stronę dokładnie w wybranym rozmiarze.</span>";}
function magazynQRDrukuj(){
  document.getElementById("warehouseQrPrintPageStyle")?.remove();const style=document.createElement("style");style.id="warehouseQrPrintPageStyle";style.textContent=magazynQRFormat==="a4"?"@page{size:A4 portrait;margin:8mm}":`@page{size:${magazynQRFormat==="70x50"?"70mm 50mm":"62mm 38mm"};margin:0}`;document.head.appendChild(style);
  document.body.classList.add("warehouse-qr-printing",`warehouse-qr-print-${magazynQRFormat}`);const done=()=>{document.body.classList.remove("warehouse-qr-printing","warehouse-qr-print-62x38","warehouse-qr-print-70x50","warehouse-qr-print-a4");style.remove();};window.addEventListener("afterprint",done,{once:true});window.print();setTimeout(done,2500);
}
function magazynQRZamknijPodglad(){document.body.classList.remove("warehouse-qr-printing","warehouse-qr-print-62x38","warehouse-qr-print-70x50","warehouse-qr-print-a4");document.getElementById("warehouseQrPrintPageStyle")?.remove();document.getElementById("warehouseQrPreview")?.remove();magazynQRPodgladPozycje=[];}

/* Dokumenty PZ/WZ w Planie zatowarowania. Szkic i skanowanie nie zmieniają
   stanu; wszystkie pozycje są księgowane atomowo dopiero po zatwierdzeniu. */
let magazynDokumentyStan={loaded:false,loading:false,busy:false,items:[],selectedId:"",error:"",rev:0};
let magazynDokumentFiltrTyp="wszystkie",magazynDokumentFiltrStatus="aktywne",magazynDokumentSzukaj="",magazynDokumentProduktSzukaj="";
let magazynDokumentPotwierdzenieId="",magazynDokumentAnulowanieId="",magazynDokumentUsuwanieId="";
let magazynDokumentSkanLokalizacje={},magazynDokumentSkanSesje={};
let magazynDokumentWybierakLokalizacji={open:false,documentId:"",productId:"",quantity:1,current:"",query:"",area:"",rack:""};
let magazynDokumentKamera={stream:null,detector:null,timer:null,active:false,busy:false,lastCode:"",lastAt:0,lastSeenAt:0,documentId:"",quantity:1,fallback:false,canvas:null,context:null,minimized:false,torch:false,zxingReader:null,zxingControls:null};

function magazynDokumentPoId(id){return (magazynDokumentyStan.items||[]).find(x=>String(x.id)===String(id))||null;}
function magazynDokumentWybrany(){const selected=magazynDokumentPoId(magazynDokumentyStan.selectedId);return selected&&magazynDokumentPasuje(selected)?selected:null;}
function magazynDokumentStatusMeta(status="draft"){return {draft:{label:"Szkic",cls:"draft",icon:"✏️"},confirmed:{label:"Zatwierdzony",cls:"confirmed",icon:"✅"},cancelled:{label:"Anulowany",cls:"cancelled",icon:"⛔"}}[status]||{label:status,cls:"",icon:"🧾"};}
function magazynDokumentRequestId(prefix="wd"){return `${prefix}-${Date.now().toString(36)}-${Math.random().toString(36).slice(2,9)}`;}
function magazynDokumentyOdswiezPanel(){const root=document.getElementById("warehouseDocumentsCenter");if(!root)return false;root.innerHTML=magazynDokumentyPanelWnetrzeHTML();globalThis.magazynPlanUstandaryzujTabeleDOM?.(root);return true;}
function magazynDokumentPrzewinDo(selector,focusSelector=""){
  requestAnimationFrame(()=>{const element=document.querySelector(selector);element?.scrollIntoView?.({block:"start",behavior:"smooth"});if(focusSelector)element?.querySelector?.(focusSelector)?.focus?.({preventScroll:true});});
}
function magazynDokumentZastosujOdpowiedz(d={}){
  if(Array.isArray(d.documents))magazynDokumentyStan.items=d.documents;
  magazynDokumentyStan.loaded=true;magazynDokumentyStan.loading=false;magazynDokumentyStan.error="";magazynDokumentyStan.rev=Number(d.rev)||magazynDokumentyStan.rev;
  if(d.document?.id)magazynDokumentyStan.selectedId=String(d.document.id);
  else if(magazynDokumentyStan.selectedId&&!magazynDokumentPoId(magazynDokumentyStan.selectedId))magazynDokumentyStan.selectedId="";
  if(d.stockUpdates&&typeof d.stockUpdates==="object"){
    stanyProduktow={...(stanyProduktow||{}),...d.stockUpdates};zapiszLS("artway_stany",stanyProduktow);
    if(Array.isArray(d.movements)&&d.movements.length){const ids=new Set(d.movements.map(x=>String(x.id)));ruchyMagazynowe=[...d.movements,...(ruchyMagazynowe||[]).filter(x=>!ids.has(String(x.id)))].slice(0,3000);zapiszLS("artway_ruchy_magazynowe",ruchyMagazynowe);}
    zbudujProdukty();
  }
  magazynDokumentyOdswiezPanel();
}
async function magazynDokumentyLaduj(force=false){
  if(magazynDokumentyStan.loading||magazynDokumentyStan.loaded&&!force)return;
  magazynDokumentyStan.loading=true;magazynDokumentyStan.error="";magazynDokumentyOdswiezPanel();
  try{const d=await chmura("warehouse-documents-list",{params:{limit:250},timeout:30000});magazynDokumentZastosujOdpowiedz(d);}
  catch(e){magazynDokumentyStan.loading=false;magazynDokumentyStan.error=e.message||"Nie udało się pobrać dokumentów";magazynDokumentyOdswiezPanel();}
}
async function magazynDokumentOperacja(action,body,message="Zapisano dokument"){
  if(magazynDokumentyStan.busy){toast("Poczekaj na zakończenie poprzedniej operacji");return null;}
  magazynDokumentyStan.busy=true;magazynDokumentyOdswiezPanel();
  try{const d=await chmura(action,{method:"POST",body,timeout:45000});magazynDokumentZastosujOdpowiedz(d);if(message)toast(message);return d;}
  catch(e){magazynDokumentyStan.error=e.message||"Nie udało się zapisać dokumentu";toast(magazynDokumentyStan.error);magazynDokumentyOdswiezPanel();return null;}
  finally{magazynDokumentyStan.busy=false;magazynDokumentyOdswiezPanel();}
}
async function magazynDokumentUtworz(form,event){event?.preventDefault();const f=new FormData(form);const d=await magazynDokumentOperacja("warehouse-document-create",{type:f.get("type"),warehouse:f.get("warehouse"),reference:f.get("reference"),note:f.get("note")},"✅ Utworzono dokument roboczy");if(d){magazynDokumentFiltrStatus="aktywne";form.reset();}return false;}
async function magazynDokumentZapiszMeta(form,event,id){event?.preventDefault();const doc=magazynDokumentPoId(id),f=new FormData(form);if(!doc)return false;await magazynDokumentOperacja("warehouse-document-update",{documentId:id,expectedRevision:doc.revision,warehouse:f.get("warehouse"),reference:f.get("reference"),note:f.get("note")},"✅ Zapisano dane dokumentu");return false;}
async function magazynDokumentDodajProdukt(documentId,productId,quantity=1,mode="increment",location=""){
  const doc=magazynDokumentPoId(documentId);if(!doc||doc.status!=="draft")return null;
  return magazynDokumentOperacja("warehouse-document-line-upsert",{documentId,expectedRevision:doc.revision,productId,quantity:Math.max(1,Number(quantity)||1),mode,location:location||magazynDokumentLokalizacjaSkanu(documentId),requestId:magazynDokumentRequestId("line")},"✅ Pozycja dodana do dokumentu");
}
function magazynDokumentSkanSesja(documentId){
  const key=String(documentId||"");if(!magazynDokumentSkanSesje[key])magazynDokumentSkanSesje[key]={confirmedLocation:String(magazynDokumentSkanLokalizacje[key]||""),proposedLocation:"",nextLocation:"",pending:null,busy:false,last:null};return magazynDokumentSkanSesje[key];
}
function magazynDokumentKodPorownawczy(value=""){const raw=String(value||"").trim().toLowerCase().replace(/\s+/g,"");const digits=raw.replace(/\D/g,"").replace(/^0+(?=\d)/,"");return {raw,digits};}
function magazynDokumentProduktPoOdczycie(parsed={}){
  const products=typeof produktyDoAdministracji==="function"?produktyDoAdministracji():[];
  if(parsed.productId)return products.find(product=>String(product.id)===String(parsed.productId))||null;
  const wanted=magazynDokumentKodPorownawczy(parsed.scanCode||parsed.raw||"");if(!wanted.raw)return null;
  return products.find(product=>[product.gtin,product.ean,product.externalId,product.sku,product.kodProducenta,product.mpn,product.kodKreskowy].some(value=>{const candidate=magazynDokumentKodPorownawczy(value);return candidate.raw&&candidate.raw===wanted.raw||wanted.digits.length>=6&&candidate.digits===wanted.digits;}))||null;
}
function magazynDokumentSkanStatus(message=""){const status=document.getElementById("warehouseCameraStatus");if(status&&message)status.textContent=message;}
function magazynDokumentSkanPrzebiegOdswiez(documentId){
  document.querySelectorAll(`[data-warehouse-receive-flow="${CSS.escape(String(documentId))}"]`).forEach(root=>{root.innerHTML=magazynDokumentSkanPrzebiegHTML(documentId,root.dataset.compact==="1");});
}
function magazynDokumentSkanUstawIlosc(documentId,value){
  const session=magazynDokumentSkanSesja(documentId),quantity=Math.max(1,Math.min(10000,Math.trunc(Number(value)||1)));if(session.pending)session.pending.quantity=quantity;magazynDokumentKamera.quantity=quantity;magazynDokumentSkanPrzebiegOdswiez(documentId);return quantity;
}
function magazynDokumentSkanZmienIlosc(documentId,delta){const session=magazynDokumentSkanSesja(documentId);return magazynDokumentSkanUstawIlosc(documentId,(Number(session.pending?.quantity)||1)+Number(delta||0));}
function magazynDokumentAnulujBiezacaPozycje(documentId){
  const session=magazynDokumentSkanSesja(documentId);session.pending=null;if(session.nextLocation){session.proposedLocation=session.nextLocation;session.nextLocation="";}magazynDokumentSkanPrzebiegOdswiez(documentId);magazynDokumentSkanStatus("Odrzucono niezatwierdzony odczyt. Stan dokumentu nie został zmieniony.");
}
async function magazynDokumentZatwierdzBiezacaPozycje(documentId,{automatic=false}={}){
  const session=magazynDokumentSkanSesja(documentId),pending=session.pending,doc=magazynDokumentPoId(documentId);if(!pending||!doc||doc.status!=="draft")return !pending;if(session.busy)return false;if(!session.confirmedLocation){toast("Najpierw zeskanuj i zatwierdź półkę");return false;}
  session.busy=true;magazynDokumentSkanPrzebiegOdswiez(documentId);const identity=pending.productId?{productId:pending.productId}:{scanCode:pending.code};
  const d=await magazynDokumentOperacja("warehouse-document-line-upsert",{documentId,expectedRevision:doc.revision,...identity,location:session.confirmedLocation,quantity:Math.max(1,Number(pending.quantity)||1),mode:"increment",requestId:magazynDokumentRequestId("scan-confirm")},"");
  session.busy=false;if(!d){magazynDokumentSkanPrzebiegOdswiez(documentId);magazynDokumentSkanStatus(`Nie zapisano ${pending.name||pending.code}. Popraw dane i spróbuj ponownie.`);return false;}
  const location=d.line?.location||session.confirmedLocation;session.last={name:d.line?.name||pending.name||pending.code,added:pending.quantity,total:d.line?.quantity||pending.quantity,location};session.pending=null;magazynDokumentKamera.quantity=1;
  if(session.nextLocation){session.proposedLocation=session.nextLocation;session.nextLocation="";}
  magazynDokumentSkanPrzebiegOdswiez(documentId);magazynDokumentKameraOdswiezPodsumowanie(d.document||magazynDokumentPoId(documentId),session.last);
  magazynDokumentSkanStatus(`✅ ${automatic?"Poprzednia pozycja zatwierdzona automatycznie":"Pozycja zatwierdzona"}: ${session.last.added} szt. ${session.last.name} • ${magazynDokumentWidocznaLokalizacja(location)}`);if(!automatic)toast(`✅ Zatwierdzono ${session.last.added} szt. — ${session.last.name}`);return true;
}
async function magazynDokumentZatwierdzPozycjeIZmienLokalizacje(documentId){const session=magazynDokumentSkanSesja(documentId),next=session.nextLocation;if(!next)return;const saved=await magazynDokumentZatwierdzBiezacaPozycje(documentId);if(saved){session.proposedLocation=next;session.nextLocation="";magazynDokumentSkanPrzebiegOdswiez(documentId);magazynDokumentSkanStatus(`Pozycja zapisana. Teraz potwierdź nową półkę ${magazynDokumentWidocznaLokalizacja(next)}.`);}}
function magazynDokumentSkanForm(form,event,id){event?.preventDefault();const input=form.querySelector("[name=scanCode]"),code=String(input?.value||"").trim();if(!code){toast("Zeskanuj lub wpisz kod");input?.focus();return false;}void magazynDokumentDodajKod(id,code,1,false);if(input){input.value="";input.focus();}return false;}
async function magazynDokumentDodajKod(documentId,code,quantity=1,fromCamera=false){
  const parsed=typeof magazynQRParsujOdczyt==="function"?magazynQRParsujOdczyt(code):{type:"code",scanCode:String(code||"").trim()};
  if(parsed.type==="location"){magazynDokumentUstawLokalizacjeSkanu(documentId,parsed.code,{fromCamera});return true;}
  const session=magazynDokumentSkanSesja(documentId);if(session.busy){magazynDokumentSkanStatus("Trwa zatwierdzanie poprzedniej pozycji — poczekaj chwilę.");return false;}
  if(!session.confirmedLocation||session.proposedLocation){magazynDokumentSkanStatus("Najpierw zeskanuj lub wybierz półkę i naciśnij „Potwierdź półkę”.");toast("Najpierw potwierdź półkę");return false;}
  if(session.pending){const saved=await magazynDokumentZatwierdzBiezacaPozycje(documentId,{automatic:true});if(!saved)return false;quantity=1;}
  const product=magazynDokumentProduktPoOdczycie(parsed),raw=String(parsed.scanCode||parsed.raw||code||"").trim();session.pending={productId:product?.id||(parsed.type==="product"?parsed.productId:""),code:raw,name:product?.nazwa||`Kod ${raw}`,image:product?.zdjecie||"",ean:product?.gtin||product?.ean||raw,externalId:product?.externalId||product?.sku||"",quantity:Math.max(1,Number(quantity)||1),fromCamera};magazynDokumentKamera.quantity=session.pending.quantity;
  magazynDokumentSkanPrzebiegOdswiez(documentId);magazynDokumentSkanStatus(`Rozpoznano ${session.pending.name}. Ustaw ilość i zatwierdź albo zeskanuj następny produkt.`);return true;
}
async function magazynDokumentUstawPozycje(documentId,productId,quantity,location=""){
  const doc=magazynDokumentPoId(documentId);if(!doc)return null;return magazynDokumentOperacja("warehouse-document-line-upsert",{documentId,expectedRevision:doc.revision,productId,quantity:Math.max(1,Number(quantity)||1),mode:"set",location,requestId:magazynDokumentRequestId("set")},"✅ Pozycja zaktualizowana");
}
async function magazynDokumentUsunPozycje(documentId,lineId){const doc=magazynDokumentPoId(documentId);if(!doc)return;await magazynDokumentOperacja("warehouse-document-line-remove",{documentId,expectedRevision:doc.revision,lineId},"Pozycja usunięta ze szkicu");}
